def is_open_after_6pm_weekday(hours_list):
    if not isinstance(hours_list, list):
        return False

    weekdays = {'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday'}

    for i in range(0, len(hours_list), 2):
        day = hours_list[i]
        time_str = hours_list[i+1]

        if day in weekdays and time_str != 'Closed':
            # Parse time_str, e.g., '11AM-9:30PM' or 'Open 24 hours'
            if '24 hours' in time_str.lower():
                return True

            # Extract closing time
            parts = time_str.split('–')
            if len(parts) == 2:
                close_str = parts[1].strip()
                # Convert to 24h format
                try:
                    if ':' in close_str:
                        close_time = datetime.strptime(close_str, '%I:%M%p').time()
                    else:
                        close_time = datetime.strptime(close_str, '%I%p').time()

                    # 6:00 PM is 18:00:00
                    if close_time > datetime.strptime('6:00PM', '%I:%M%p').time():
                        return True
                except Exception as e:
                    print(f"Error parsing {close_str}: {e}")
                    pass
    return False

df['open_late'] = df['hours'].apply(is_open_after_6pm_weekday)
df_late = df[df['open_late'] & (df['state'].str.contains('Open', na=False, case=False))]

